import{_ as n,I as p,o as r,c as s,at as _,J as t}from"./chunks/framework.DYZFTu11.js";const f=JSON.parse('{"title":"《序章：不存在的人》","description":"","frontmatter":{},"headers":[],"relativePath":"zh_cn/novels/liehenzhihuo/chapter-01.md","filePath":"zh_cn/novels/liehenzhihuo/chapter-01.md","lastUpdated":1773498699000}'),c={name:"zh_cn/novels/liehenzhihuo/chapter-01.md"};function i(l,e,h,d,m,g){const o=p("NolebaseGitContributors"),a=p("NolebaseGitChangelog");return r(),s("div",null,[e[0]||(e[0]=_('<h1 id="《序章-不存在的人》" tabindex="-1"><strong>《序章：不存在的人》</strong> <a class="header-anchor" href="#《序章-不存在的人》" aria-label="Permalink to “《序章：不存在的人》”">​</a></h1><p><strong>β星时间 2059年7月11日 23:17</strong><strong>第三街区，旧书店“昨日回响”</strong></p><p>夜隼（Yè Sǔn）喜欢雨。</p><p>雨声能掩盖他指尖在全息键盘上敲击时发出的细微杂音，也能冲淡空气中那股劣质营养膏和线路板过热后混合产生的、挥之不去的酸腐气味。更重要的是，雨水能干扰财团部署在街区上空那些无处不在的监控探头，为他这种生活在阴影中的“幽灵”提供一层天然的屏障。</p><p>他蜷缩在书店二楼的阁楼里，这里是他的巢穴，也是他的驾驶舱。几块从黑市淘来的、型号各异的数据屏闪烁着幽蓝色的光，映在他那张过分年轻的脸上。屏幕上，瀑布般的数据流正以肉眼难以捕捉的速度飞速滚落。他像一个经验丰富的深海潜航员，灵巧地驾驭着代码的潜流，绕过财团布下的一个个数据暗礁，潜入目标的底层数据库。</p><p>“搞定。”</p><p>随着最后一个指令的输入，街角那家“好运来”杂货铺下个季度的进货渠道数据，已经被他打包加密，发送到了另一个信息掮客的终端里。很快，一笔不多不少的信用点就会汇入他的匿名账户，足够他和楼下的“家人”安稳度过这个漫长的雨季。</p><p>他摘下神经连接器，长长地舒了口气，阁楼外传来木质楼梯“吱呀”作响的声音。</p><p>“隼，还没睡？”一个苍老而温和的声音传来。</p><p>是老爹，这家旧书店的主人。一个固执地活在上个世纪，坚信纸质书的油墨香远比电子数据更有人情味的老古董。也是他，在十几年前一个同样下着大雨的夜晚，从垃圾箱旁捡回了奄-奄一息的夜隼。</p><p>“就快了，老爹。”夜隼从一堆废旧零件中站起身，活动了一下有些僵硬的脖颈。</p><p>“莉莉今天又念叨你了，说你答应给她做的电子蝴蝶还没兑现。”老爹端着一杯热气腾-腾的牛奶走上阁楼，昏黄的灯光将他满是皱纹的脸庞映照得格外慈祥。</p><p>莉莉，是老爹三年前从福利院领养回来的小女孩，一个对这个冰冷的世界仍然抱有天真幻想的小家伙。</p><p>“明天，明天一定。”夜隼接过牛奶，杯壁的温度驱散了阁楼深夜的寒意。</p><p>“早点休息，别总熬夜。”老-爹絮絮叨叨地嘱咐着，转身走下楼梯，“财团最近又不怎么太平，风声很紧，听说要清剿什么‘数据黑市’，你出门小心点。”</p><p>“知道了。”</p><p>夜隼应了一声，目光却透过阁楼那扇满是污渍的窗户，望向了雨幕中那座高耸入云的财团总部大楼。那座巨塔像一柄冰冷的利剑，将城市分割成两个截然不同的世界。塔尖的霓虹灯刺破夜空，冰冷地俯瞰着脚下这片被雨水和黑暗浸泡的、如同铁锈般腐朽的第三街区。</p><p>“清剿黑市”……夜隼的嘴角勾起一抹嘲讽的弧度。</p><p>对那些生活在塔尖的人来说，他们这些生活在阴影里的老鼠，或许就是最需要被“美化”掉的污点吧。</p><p>此刻的他还不知道，这场名为“净化”的风暴，将以他无法想象的残酷方式，彻底粉碎他所珍视的一切，并将他从一个只求偏安一隅的“幽灵”，锻造成一簇足以燎原的、燃烧着复仇之火的裂痕。</p><hr>',21)),t(o),t(a)])}const b=n(c,[["render",i]]);export{f as __pageData,b as default};
